60	    const result = runScenario({
61	      customer: { yearsWithMHPCO: 0 },
62	      steps: [{ op: "quote", items: [
63	        { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" },
64	      ] }],
65	    });
66	    expect(result).toEqual({ results: [{ premium: 105 }] });
67	  });
68	  it.todo("7 runes → 175 G base premium (+5 fee = 180)");
69	
70	  // --- 'Alike' clarification ---
71	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types) (+5 fee = 80)");
72	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks) (+5 fee = 125)");
73	
74	  // --- Item-specific modifiers ---
75	  it.todo("single cursed sword (steel, ench 3), newcomer first contract → 165 G");
76	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
77	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
78	  it.todo("cursed sword with enchantment 5 → both surcharges apply");
79	
80	  // --- Policy-wide modifiers ---
81	  it.todo("customer with exactly 2 years → loyalty discount applies");
82	
83	  // --- Modifier scope on multi-item policy ---
84	  it.todo("cursed sword + plain amulet → 210 G before further modifiers/fee (cursed surcharge on cursed item only)");
85	
86	  // --- Rounding ---
87	  it.todo("premium calculation that yields 197.5 G → final premium 198 G (rounded up in MHPCO's favor)");
88	
89	  // --- Integration examples ---
90	  it.todo("newcomer with cursed sword (steel, ench 3) → 165 G");
91	  it.todo("long-standing customer's second contract — cursed sword (steel, ench 7), 3 years → 160 G");
92	
93	  // --- Claim: standard reimbursement ---
94	  it.todo("regular sword damage 500 G → payout 400 G (full minus deductible)");
95	  it.todo("rune damage 200 G → payout 100 G (no special clause, deductible)");
96	
97	  // --- Claim: deductible per damage event ---
98	  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → payout 600 G (deductible per item)");
99	
100	  // --- Claim: enchantment vs dragon material ---
101	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50 % wins, then deductible)");
102	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (dragon-material: full minus deductible)");
103	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50 % then deductible)");
104	  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (high-ench applies, then deductible)");
105	
106	  // --- Multiple items of same type ---
107	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G; dragon attack damages both with separate deductibles");
108	  it.todo("damages contains more entries of a type than policy covers → CLI exits non-zero");
109	
110	  // --- Cap exhaustion ---
111	  it.todo("policy: sword + amulet → insurance sum 1600 G (cap 3200 G)");
112	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
113	  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block affects premium only)");
114	  it.todo("sword, two successive claims of 1500 G each → first payout 1400 G, second 600 G; cap exhausted");
115	
116	  // --- Payout rounding ---
117	  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
118	
119	  // --- Edge case errors ---
120	  it.todo("quote with unknown item type → CLI exits non-zero with stderr error; no results on stdout");
121	  it.todo("claim references damage for item not in policy → CLI exits non-zero with stderr error");
122	  it.todo("claim has negative damage amount → CLI exits non-zero with stderr error");
123	});
