1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	};
10	
11	type Item = { type: string };
12	type QuoteStep = { op: "quote"; items: Item[] };
13	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
14	
15	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type];
16	
17	const COMPONENT_BLOCK_SIZE = 3;
18	const COMPONENT_BLOCK_PREMIUM = 60;
19	
20	const totalBasePremium = (items: Item[]): number => {
21	  if (items.length === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
22	  return items.reduce((sum, item) => sum + basePremiumFor(item), 0);
23	};
24	
25	const quotePremium = (step: QuoteStep): number =>
26	  totalBasePremium(step.items) + PROCESSING_FEE;
27	
28	const resultFor = (step: QuoteStep) => ({ premium: quotePremium(step) });
29	
30	export const runScenario = (input: unknown): unknown => {
31	  const scenario = input as Scenario;
32	  return { results: scenario.steps.map(resultFor) };
33	};
